});
```

#### `getStreamSink()`

A sink that writes to a `WritableStream` or Node.js `Writable` (e.g., `process.stdout`, `process.stderr`, or a file stream). This is typically used for structured output in server environments.

```typescript
import {
  configure,
  getStreamSink,
  jsonLinesFormatter,
} from "@logtape/logtape";
import { createWriteStream } from "node:fs";

await configure({
  sinks: {
    // Write JSON lines to stdout
