## Complete Example: Production-Style Setup

Here is a full example combining multiple concepts for a server application:

```typescript
import {
  configure,
  dispose,
  getConsoleSink,
  getLogger,
  getStreamSink,
  jsonLinesFormatter,
  withContext,
} from "@logtape/logtape";
import { getFileSink } from "@logtape/file";

// --- Configuration (call once at startup) ---

await configure({
  sinks: {
    // Human-readable output for local development
    console: getConsoleSink(),
    // Structured JSON to stdout for log aggregation (production)
    stdout: getStreamSink(process.stdout, {
      formatter: jsonLinesFormatter,
    }),
    // Structured JSON to a file as backup
    file: getFileSink("/var/log/my-app/app.jsonl", {
      formatter: jsonLinesFormatter,
    }),
  },
  loggers: [
    {
      category: ["my-app"],
      lowestLevel: "info",
      sinks: process.env.NODE_ENV === "production"
        ? ["stdout", "file"]
        : ["console"],
    },
    {
      // More verbose logging for the HTTP subsystem in dev
      category: ["my-app", "http"],
      lowestLevel: process.env.NODE_ENV === "production" ? "info" : "debug",
      sinks: process.env.NODE_ENV === "production"
        ? ["stdout", "file"]
        : ["console"],
    },
    {
      category: ["logtape", "meta"],
      lowestLevel: "warning",
      sinks: ["console"],
    },
  ],
});

// --- Usage ---

const logger = getLogger(["my-app"]);
const httpLogger = getLogger(["my-app", "http"]);

logger.info("Server starting on port {port}", { port: 4010 });

async function handleRequest(req: Request): Promise<Response> {
  return withContext(
    { requestId: crypto.randomUUID(), method: req.method },
    async () => {
      httpLogger.info("Request received: {url}", { url: req.url });

      try {
        const response = await routeRequest(req);
        httpLogger.info("Response {status}", { status: response.status });
        return response;
      } catch (error) {
        httpLogger.error("Request failed: {error}", {
          error: error instanceof Error ? error.message : String(error),
        });
        return new Response("Internal Server Error", { status: 500 });
      }
    },
  );
}

// --- Cleanup on shutdown ---

process.on("SIGTERM", async () => {
  logger.info("Received SIGTERM, shutting down");
  await dispose();
  process.exit(0);
});
```

